  1→package search_test
  2→
  3→import (
  4→	"context"
  5→	"encoding/json"
  6→	"fmt"
  7→	"os"
  8→	"sort"
  9→	"testing"
 10→
 11→	"github.com/jackc/pgx/v5/pgxpool"
 12→	"github.com/ketang/kapow/api/internal/search"
 13→)
 14→
 15→// IntegrationSearch_MetadataDrivenSingleField generates a deterministic search
 16→// for every searchable field in the registry using only the field's published
 17→// metadata (kind, options, bounds). It then executes the query against a real
 18→// database and verifies the result is well-formed.
 19→//
 20→// No search filter payload is hard-coded in this test. Every filter is derived
 21→// from the FieldDescriptor returned by the registry.
 22→func TestIntegrationSearch_MetadataDrivenSingleField(t *testing.T) {
 23→	pool := integrationPool(t)
 24→	ctx := context.Background()
 25→	reg := search.NewRegistry()
 26→
 27→	for _, f := range sortedFields(reg) {
 28→		desc := f.Descriptor()
 29→		if desc.Searchability != search.SearchabilitySearchable {
 30→			continue
 31→		}
 32→
 33→		t.Run(desc.Name, func(t *testing.T) {
 34→			filter := filterFromDescriptor(t, desc)
 35→			if filter == nil {
 36→				t.Skipf("cannot generate filter for kind %s", desc.Kind)
 37→				return
 38→			}
 39→
 40→			req := search.SearchRequest{
 41→				Filters: []search.FilterInput{
 42→					{Field: desc.Name, Value: filter},
 43→				},
 44→				Limit: 5,
 45→			}
 46→
 47→			// Validate the request first.
 48→			if errs := search.ValidateRequest(reg, req, true); len(errs) != 0 {
 49→				t.Fatalf("validation errors for generated filter: %v", errs)
 50→			}
 51→
 52→			// Build and execute the data query.
 53→			sql, args, err := search.BuildQuery(reg, req)
 54→			if err != nil {
 55→				t.Fatalf("BuildQuery: %v", err)
 56→			}
 57→			assertQueryExecutes(t, ctx, pool, sql, args)
 58→
 59→			// Build and execute the count query.
 60→			csql, cargs, err := search.BuildCountQuery(reg, req)
 61→			if err != nil {
 62→				t.Fatalf("BuildCountQuery: %v", err)
 63→			}
 64→			var count int
 65→			if err := pool.QueryRow(ctx, csql, cargs...).Scan(&count); err != nil {
 66→				t.Fatalf("count query failed: %v\nSQL: %s\nArgs: %v", err, csql, cargs)
 67→			}
 68→			if count < 0 {
 69→				t.Errorf("count query returned negative: %d", count)
 70→			}
 71→		})
 72→	}
 73→}
