 75→// IntegrationSearch_MetadataDrivenPairwise generates deterministic searches
 76→// that combine every unique pair of searchable fields. This catches SQL
 77→// generation issues that only surface when multiple WHERE clauses are joined
 78→// (e.g. placeholder index collisions, incompatible casts).
 79→func TestIntegrationSearch_MetadataDrivenPairwise(t *testing.T) {
 80→	pool := integrationPool(t)
 81→	ctx := context.Background()
 82→	reg := search.NewRegistry()
 83→
 84→	searchable := searchableDescriptors(reg)
 85→	if len(searchable) < 2 {
 86→		t.Skip("fewer than 2 searchable fields")
 87→	}
 88→
 89→	// Generate all unique pairs (i < j), deterministically ordered by name.
 90→	for i := 0; i < len(searchable); i++ {
 91→		for j := i + 1; j < len(searchable); j++ {
 92→			a, b := searchable[i], searchable[j]
 93→			name := fmt.Sprintf("%s+%s", a.Name, b.Name)
 94→
 95→			t.Run(name, func(t *testing.T) {
 96→				fa := filterFromDescriptor(t, a)
 97→				fb := filterFromDescriptor(t, b)
 98→				if fa == nil || fb == nil {
 99→					t.Skip("cannot generate filter for one of the pair")
100→					return
101→				}
102→
103→				req := search.SearchRequest{
104→					Filters: []search.FilterInput{
105→						{Field: a.Name, Value: fa},
106→						{Field: b.Name, Value: fb},
107→					},
108→					Limit: 5,
109→				}
110→
111→				if errs := search.ValidateRequest(reg, req, true); len(errs) != 0 {
112→					t.Fatalf("validation errors: %v", errs)
113→				}
114→
115→				sql, args, err := search.BuildQuery(reg, req)
116→				if err != nil {
117→					t.Fatalf("BuildQuery: %v", err)
118→				}
119→				assertQueryExecutes(t, ctx, pool, sql, args)
120→			})
121→		}
122→	}
123→}
