276→// assertQueryExecutes runs the SQL query and verifies that every returned row
277→// scans without error and has a non-empty unit_id and institution_name.
278→func assertQueryExecutes(t *testing.T, ctx context.Context, pool *pgxpool.Pool, sql string, args []any) {
279→	t.Helper()
280→
281→	rows, err := pool.Query(ctx, sql, args...)
282→	if err != nil {
283→		t.Fatalf("query failed: %v\nSQL: %s\nArgs: %v", err, sql, args)
284→	}
285→	defer rows.Close()
286→
287→	rowCount := 0
288→	for rows.Next() {
289→		var (
290→			unitID, name, city, state string
291→			lat, lng, distance        *float64
292→			myPrice                   *int
293→		)
294→		if err := rows.Scan(&unitID, &name, &city, &state, &lat, &lng, &distance, &myPrice); err != nil {
295→			t.Fatalf("scan row %d: %v\nSQL: %s", rowCount, err, sql)
296→		}
297→		if unitID == "" {
298→			t.Errorf("row %d: empty unit_id", rowCount)
299→		}
300→		if name == "" {
301→			t.Errorf("row %d: empty institution_name", rowCount)
302→		}
303→		rowCount++
304→	}
305→	if err := rows.Err(); err != nil {
306→		t.Fatalf("rows iteration: %v\nSQL: %s", err, sql)
307→	}
308→	t.Logf("returned %d rows", rowCount)
309→}
