311→// mustMarshal JSON-encodes v and fails the test on error.
312→func mustMarshal(t *testing.T, v any) json.RawMessage {
313→	t.Helper()
314→	b, err := json.Marshal(v)
315→	if err != nil {
316→		t.Fatalf("json.Marshal: %v", err)
317→	}
318→	return b
319→}
