236→// permanentFilter is an unconditional WHERE clause applied to every query.
237→// It excludes non-degree-granting locations (0), certificate-only programs (1),
238→// and associate's-only institutions (2), keeping only Bachelor's or higher (≥ 3).
239→const permanentFilter = "COALESCE((data #>> '{nces,degrees_awarded_highest}')::int, 0) >= 3"
