241→// buildWhere resolves each FilterInput to a SQL clause, advancing the placeholder
242→// index across filters so that $N numbering is globally consistent within one query.
243→func buildWhere(reg *Registry, filters []FilterInput) (clauses []string, args []any, err error) {
244→	clauses = []string{permanentFilter}
245→	argStart := 1
246→	for _, fi := range filters {
247→		field, ok := reg.Lookup(fi.Field)
248→		if !ok {
249→			return nil, nil, fmt.Errorf("unknown field %q", fi.Field)
250→		}
251→		clause, fieldArgs, ferr := field.BuildSQL(fi.Value, argStart)
252→		if ferr != nil {
253→			return nil, nil, fmt.Errorf("field %q: %w", fi.Field, ferr)
254→		}
255→		clauses = append(clauses, clause)
256→		args = append(args, fieldArgs...)
257→		argStart += len(fieldArgs)
258→	}
259→	return clauses, args, nil
260→}
