package handler_test

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"net/url"
	"strings"
	"testing"

	"github.com/ketang/kapow/api/internal/auth"
	"github.com/ketang/kapow/api/internal/handler"
	"github.com/ketang/kapow/api/internal/search"
)

// ─────────────────────────────────────────────────────────────────────────────
// ExportCSV — unit tests (no real DB)
// ─────────────────────────────────────────────────────────────────────────────

func TestExportCSV_InvalidFiltersJSON(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	h := handler.ExportCSV(nil, reg, 500)

	u := "/api/export/csv?filters=" + url.QueryEscape("not valid json")
	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodGet, u, nil)
	h(w, r)

	if w.Code != http.StatusBadRequest {
		t.Errorf("HTTP status: got %d, want %d", w.Code, http.StatusBadRequest)
	}

	var body map[string]string
	if err := json.NewDecoder(w.Body).Decode(&body); err != nil {
		t.Fatalf("decode body: %v", err)
	}
	if body["error"] == "" {
		t.Error("expected non-empty error message")
	}
}

func TestExportCSV_InvalidFilterField(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	h := handler.ExportCSV(nil, reg, 500)

	filters := `[{"field":"does_not_exist","value":{"value":"x"}}]`
	u := "/api/export/csv?filters=" + url.QueryEscape(filters)
	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodGet, u, nil)
	h(w, r)

	if w.Code != http.StatusBadRequest {
		t.Errorf("HTTP status: got %d, want %d", w.Code, http.StatusBadRequest)
	}

	var body struct {
		Errors []struct {
			Field   string `json:"field"`
			Message string `json:"message"`
		} `json:"errors"`
	}
	if err := json.NewDecoder(w.Body).Decode(&body); err != nil {
		t.Fatalf("decode body: %v", err)
	}
	if len(body.Errors) == 0 {
		t.Error("expected at least 1 validation error")
	}
}

func TestExportCSV_InvalidUserLatLng(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	h := handler.ExportCSV(nil, reg, 500)

	u := "/api/export/csv?userLat=abc&userLng=def"
	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodGet, u, nil)
	h(w, r)

	if w.Code != http.StatusBadRequest {
		t.Errorf("HTTP status: got %d, want %d", w.Code, http.StatusBadRequest)
	}
}

func TestExportCSV_SortDistanceWithoutLocation(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	h := handler.ExportCSV(nil, reg, 500)

	u := "/api/export/csv?sort=DISTANCE"
	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodGet, u, nil)
	h(w, r)

	// ValidateRequest should catch sort=DISTANCE without userLocation.
	if w.Code != http.StatusBadRequest {
		t.Errorf("HTTP status: got %d, want %d", w.Code, http.StatusBadRequest)
	}
}

// restrictedTestRegistry returns a registry with a single restricted enum field.
func restrictedTestRegistry() *search.Registry {
	f := search.NewTestSingleEnumField("secret_field", search.SearchabilityRestricted, []search.EnumOption{
		{Value: "a", Label: "A"},
		{Value: "b", Label: "B"},
	})
	return search.NewRegistryFromFields([]search.Field{f})
}

func TestExportCSV_RestrictedField_Anonymous(t *testing.T) {
	t.Parallel()
	reg := restrictedTestRegistry()
	h := handler.ExportCSV(nil, reg, 500)

	filters := `[{"field":"secret_field","value":{"value":"a"}}]`
	u := "/api/export/csv?filters=" + url.QueryEscape(filters)
	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodGet, u, nil)
	// No auth claims in context — anonymous request.
	h(w, r)

	if w.Code != http.StatusBadRequest {
		t.Fatalf("HTTP status: got %d, want %d", w.Code, http.StatusBadRequest)
	}

	var body struct {
		Errors []struct {
			Field   string `json:"field"`
			Message string `json:"message"`
		} `json:"errors"`
	}
	if err := json.NewDecoder(w.Body).Decode(&body); err != nil {
		t.Fatalf("decode body: %v", err)
	}
	if len(body.Errors) == 0 {
		t.Fatal("expected validation errors for restricted field")
	}
	found := false
	for _, e := range body.Errors {
		if e.Field == "secret_field" && strings.Contains(e.Message, "authentication") {
			found = true
			break
		}
	}
	if !found {
		t.Errorf("expected auth-required error for secret_field, got: %+v", body.Errors)
	}
}

func TestExportCSV_RestrictedField_Authenticated(t *testing.T) {
	t.Parallel()
	reg := restrictedTestRegistry()
	h := handler.ExportCSV(nil, reg, 100)

	filters := `[{"field":"secret_field","value":{"value":"a"}}]`
	u := "/api/export/csv?filters=" + url.QueryEscape(filters)
	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodGet, u, nil)

	// Inject auth claims into context — authenticated request.
	ctx := auth.SetClaims(r.Context(), &auth.Claims{})
	r = r.WithContext(ctx)

	// The handler will pass validation but panic on nil DB pool when
	// building the export query. A panic means validation succeeded,
	// which is the correct behaviour for an authenticated caller.
	defer func() {
		if r := recover(); r == nil {
			// No panic — handler wrote a response; check it wasn't a 400.
			if w.Code == http.StatusBadRequest {
				t.Fatalf("authenticated request should not be rejected; got 400 with body: %s", w.Body.String())
			}
		}
		// Panic from nil pool is expected — validation passed.
	}()
	h(w, r)
}

