package search

// NewTestSingleEnumField creates a SingleEnumField for use in tests.
// It allows callers outside the search package to construct fields with
// specific searchability settings.
func NewTestSingleEnumField(name string, searchability FieldSearchability, options []EnumOption) *SingleEnumField {
	return &SingleEnumField{
		baseField: baseField{
			name:          name,
			label:         name,
			kind:          KindSingleEnum,
			theme:         ThemeOther,
			source:        FieldSource{Kind: SourceColumn, Column: "test_col"},
			visibility:    VisibilityVisible,
			searchability: searchability,
			exportable:    ptr(false),
			outputDefault: ptr(false),
		},
		Options: options,
	}
}

package search

import "encoding/json"

// FilterInput pairs a field name with its JSON-encoded filter value.
type FilterInput struct {
	Field string          `json:"field"`
	Value json.RawMessage `json:"value"`
}

// UserLocation is the user's location context, used for distance and myPrice computation.
type UserLocation struct {
	Latitude  float64
	Longitude float64
	State     string // 2-letter code; empty means unknown
}

// SortDirection is ASC or DESC.
type SortDirection string

const (
	SortDirectionAsc  SortDirection = "ASC"
	SortDirectionDesc SortDirection = "DESC"
)

// SortInput controls result ordering.
// Field is a string: "DISTANCE" and "NAME" are built-in; any other value is
// looked up in the field registry (must have sortable=true).
type SortInput struct {
	Field     string
	Direction SortDirection // defaults to ASC if empty
}

// SearchRequest is the top-level input to the search API.
type SearchRequest struct {
	Filters      []FilterInput `json:"filters"`
	Limit        int           `json:"limit,omitempty"`
	Offset       int           `json:"offset,omitempty"`
	Sort         *SortInput
	UserLocation *UserLocation
	Blend        *BlendInput
}

// SearchResult is one institution returned by a search.
type SearchResult struct {
	UnitID          string   `json:"unit_id"`
	InstitutionName string   `json:"institution_name"`
	City            string   `json:"city"`
	State           string   `json:"state"`
	Latitude        *float64 `json:"latitude,omitempty"`
	Longitude       *float64 `json:"longitude,omitempty"`
	Distance        *float64 `json:"distance,omitempty"`
	MyPrice         *int     `json:"myPrice,omitempty"`
	BlendScore      *float64 `json:"blendScore,omitempty"`
}

// SearchResponse wraps the result set with pagination metadata.
type SearchResponse struct {
	Results []SearchResult `json:"results"`
	Total   int            `json:"total"`
	Limit   int            `json:"limit"`
	Offset  int            `json:"offset"`
}

const (
	DefaultLimit = 20
	MaxLimit     = 100
)

package search

// ExactNumericFilter matches rows where the field equals Value.
type ExactNumericFilter struct {
	Value float64 `json:"value"`
}

// NumericRangeFilter matches rows where the field is within [Min, Max].
// At least one of Min or Max must be non-nil.
type NumericRangeFilter struct {
	Min *float64 `json:"min,omitempty"`
	Max *float64 `json:"max,omitempty"`
}

// SubstringFilter performs a case-insensitive substring match.
type SubstringFilter struct {
	Value string `json:"value"`
}

// FullTextFilter performs a full-text search using plainto_tsquery.
type FullTextFilter struct {
	Query string `json:"query"`
}

// ExactStringFilter matches rows where the field equals Value (case-sensitive or not
// depending on the field definition).
type ExactStringFilter struct {
	Value string `json:"value"`
}

// SingleEnumFilter matches rows where the field equals one specific enum value.
type SingleEnumFilter struct {
	Value string `json:"value"`
}

// MultiEnumFilter matches rows where the field contains any/all of the given values.
type MultiEnumFilter struct {
	Values []string `json:"values"`
}

// GeoFilterKind discriminates between radius and bounding-box geo filters.
type GeoFilterKind string

const (
	GeoFilterKindRadius GeoFilterKind = "radius"
	GeoFilterKindBBox   GeoFilterKind = "bbox"
)

// GeoRadiusFilter specifies a centre point and search radius.
type GeoRadiusFilter struct {
	Lat      float64 `json:"lat"`
	Lng      float64 `json:"lng"`
	RadiusKm float64 `json:"radius_km"`
}

// GeoBoundingBoxFilter specifies an axis-aligned geographic bounding box.
type GeoBoundingBoxFilter struct {
	MinLat float64 `json:"min_lat"`
	MaxLat float64 `json:"max_lat"`
	MinLng float64 `json:"min_lng"`
	MaxLng float64 `json:"max_lng"`
}

// GeoFilterInput is the top-level geo filter that wraps the specific kind.
type GeoFilterInput struct {
	Kind   GeoFilterKind        `json:"kind"`
	Radius *GeoRadiusFilter     `json:"radius,omitempty"`
	BBox   *GeoBoundingBoxFilter `json:"bbox,omitempty"`
}

