package search_test

import (
	"strings"
	"testing"

	"github.com/ketang/kapow/api/internal/search"
)

// TestContractMatrix_Baseline validates all contract cases against
// ValidateRequest directly. This is the ground-truth reference that
// per-entry-point runners (handler, mcp) must agree with.
func TestContractMatrix_Baseline(t *testing.T) {
	t.Parallel()
	defaultReg := search.NewRegistry()

	for _, cc := range search.ContractCases() {
		t.Run(cc.Name, func(t *testing.T) {
			t.Parallel()

			reg := defaultReg
			if cc.Registry != nil {
				reg = cc.Registry
			}

			errs := search.ValidateRequest(reg, cc.Request, cc.Authenticated)

			if cc.WantValid {
				if len(errs) != 0 {
					t.Fatalf("expected valid request, got %d errors: %+v", len(errs), errs)
				}
				return
			}

			// Expect at least one error matching the contract.
			if len(errs) == 0 {
				t.Fatal("expected validation errors, got none")
			}

			found := false
			for _, e := range errs {
				if e.Field == cc.WantField && strings.Contains(e.Message, cc.WantContains) {
					found = true
					break
				}
			}
			if !found {
				t.Errorf("expected error field=%q containing %q, got: %+v",
					cc.WantField, cc.WantContains, errs)
			}
		})
	}
}

