package handler_test

import (
	"encoding/json"
	"fmt"
	"net/http"
	"net/http/httptest"
	"net/url"
	"strings"
	"testing"

	"github.com/ketang/kapow/api/internal/auth"
	"github.com/ketang/kapow/api/internal/handler"
	"github.com/ketang/kapow/api/internal/search"
)

// TestContractMatrix_Export runs the shared contract cases through the CSV
// export handler, verifying that the export adapter produces the same
// validation outcomes as the baseline.
func TestContractMatrix_Export(t *testing.T) {
	t.Parallel()
	defaultReg := search.NewRegistry()

	for _, cc := range search.ContractCases() {
		if cc.SkipExport {
			continue
		}

		t.Run(cc.Name, func(t *testing.T) {
			t.Parallel()

			reg := defaultReg
			if cc.Registry != nil {
				reg = cc.Registry
			}

			h := handler.ExportCSV(nil, reg, 500)
			u := buildExportURL(cc.Request)
			w := httptest.NewRecorder()
			r := httptest.NewRequest(http.MethodGet, u, nil)

			if cc.Authenticated {
				ctx := auth.SetClaims(r.Context(), &auth.Claims{})
				r = r.WithContext(ctx)
			}

			if cc.WantValid {
				// Validation passes → handler proceeds to DB call → nil pool panics.
				// A panic (or non-400 response) means validation succeeded.
				defer func() {
					if rec := recover(); rec == nil {
						if w.Code == http.StatusBadRequest {
							t.Fatalf("expected validation to pass, got 400: %s", w.Body.String())
						}
					}
					// Panic from nil pool = validation passed ✓
				}()
				h(w, r)
				return
			}

			// Expect validation failure → HTTP 400.
			h(w, r)

			if w.Code != http.StatusBadRequest {
				t.Fatalf("HTTP status: got %d, want %d; body: %s",
					w.Code, http.StatusBadRequest, w.Body.String())
			}

			var body struct {
				Errors []struct {
					Field   string `json:"field"`
					Message string `json:"message"`
				} `json:"errors"`
			}
			if err := json.NewDecoder(w.Body).Decode(&body); err != nil {
				t.Fatalf("decode body: %v", err)
			}
			if len(body.Errors) == 0 {
				t.Fatal("expected validation errors in response body")
			}

			found := false
			for _, e := range body.Errors {
				if e.Field == cc.WantField && strings.Contains(e.Message, cc.WantContains) {
					found = true
					break
				}
			}
			if !found {
				t.Errorf("expected error field=%q containing %q, got: %+v",
					cc.WantField, cc.WantContains, body.Errors)
			}
		})
	}
}

// buildExportURL serializes a SearchRequest into query params matching the
// export handler's parsing logic.
func buildExportURL(req search.SearchRequest) string {
	params := url.Values{}

	if len(req.Filters) > 0 {
		data, _ := json.Marshal(req.Filters)
		params.Set("filters", string(data))
	}

	if req.Sort != nil {
		params.Set("sort", req.Sort.Field)
		if req.Sort.Direction == search.SortDirectionDesc {
			params.Set("sortDir", "DESC")
		}
	}

	if req.UserLocation != nil {
		params.Set("userLat", fmt.Sprintf("%g", req.UserLocation.Latitude))
		params.Set("userLng", fmt.Sprintf("%g", req.UserLocation.Longitude))
		if req.UserLocation.State != "" {
			params.Set("userState", req.UserLocation.State)
		}
	}

	return "/api/export/csv?" + params.Encode()
}

