			t.Parallel()

			reg := defaultReg
			if cc.Registry != nil {
				reg = cc.Registry
			}

			handler := makeSearchHandler(nil, reg)

			in := searchInput{
				Filters: cc.Request.Filters,
				Limit:   cc.Request.Limit,
				Offset:  cc.Request.Offset,
			}

			ctx := context.Background()
			if cc.Authenticated {
				ctx = auth.SetClaims(ctx, &auth.Claims{})
			}

			if cc.WantValid {
				// Validation passes → handler proceeds to DB call → nil Querier panics.
				defer func() {
					if rec := recover(); rec == nil {
