package search

import "encoding/json"

// ContractCase defines a single validation contract test case.
// The shared matrix is consumed by per-package test runners in search,
// handler, and mcp to prove equivalent requests produce equivalent
// validation outcomes across all entry points.
type ContractCase struct {
	Name          string        // Human-readable test name
	Request       SearchRequest // The search request to validate
	Authenticated bool          // Whether the caller is authenticated

	// Expected outcome.
	WantValid    bool   // true = expect 0 validation errors
	WantField    string // if invalid: expected error field
	WantContains string // if invalid: substring in error message

	// Entry-point applicability.
	SkipExport bool // true if this case doesn't apply to CSV export
	SkipMCP    bool // true if this case doesn't apply to MCP

	// Registry override. Nil means use NewRegistry().
	Registry *Registry
}

// ContractCases returns the shared validation contract test matrix.
func ContractCases() []ContractCase {
	restrictedReg := NewRegistryFromFields([]Field{
		NewTestSingleEnumField("secret_field", SearchabilityRestricted, []EnumOption{
			{Value: "a", Label: "A"},
			{Value: "b", Label: "B"},
		}),
	})

	return []ContractCase{
		// ── Valid filters ────────────────────────────────────────────
		{
			Name: "valid multi-enum filter",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "state", Value: json.RawMessage(`["CA"]`)},
				},
			},
			Authenticated: true,
			WantValid:     true,
		},
		{
			Name: "valid numeric range filter",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "enrollment", Value: json.RawMessage(`{"min":1000,"max":50000}`)},
				},
			},
			Authenticated: true,
			WantValid:     true,
		},
		{
			Name: "valid full-text filter",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "name", Value: json.RawMessage(`{"query":"MIT"}`)},
				},
			},
			Authenticated: true,
			WantValid:     true,
		},

		// ── Invalid filters ─────────────────────────────────────────
		{
			Name: "unknown field",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "bogus", Value: json.RawMessage(`"x"`)},
				},
			},
			Authenticated: true,
			WantField:     "bogus",
			WantContains:  "unknown field",
		},
		{
			Name: "bad enum value",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "state", Value: json.RawMessage(`["XX"]`)},
				},
			},
			Authenticated: true,
			WantField:     "state",
			WantContains:  "not in allowed options",
		},
		{
			Name: "empty multi-enum values",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "application_platforms", Value: json.RawMessage(`{"values":[]}`)},
				},
			},
			Authenticated: true,
			WantField:     "application_platforms",
			WantContains:  "at least one value required",
		},
		{
			Name: "numeric range both nil",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "enrollment", Value: json.RawMessage(`{}`)},
				},
			},
			Authenticated: true,
			WantField:     "enrollment",
			WantContains:  "at least one of min or max",
		},
		{
			Name: "numeric range out of bounds",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "admission_rate", Value: json.RawMessage(`{"min":-1}`)},
				},
			},
			Authenticated: true,
			WantField:     "admission_rate",
			WantContains:  "value out of allowed range",
		},

		// ── Auth sensitivity ────────────────────────────────────────
		{
			Name: "restricted field anonymous",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "secret_field", Value: json.RawMessage(`{"value":"a"}`)},
				},
			},
			Authenticated: false,
			WantField:     "secret_field",
			WantContains:  "authentication",
			Registry:      restrictedReg,
		},
		{
			Name: "restricted field authenticated",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "secret_field", Value: json.RawMessage(`{"value":"a"}`)},
				},
			},
			Authenticated: true,
			WantValid:     true,
			Registry:      restrictedReg,
		},

		// ── Sort ────────────────────────────────────────────────────
		{
			Name: "sort distance without location",
			Request: SearchRequest{
				Sort: &SortInput{Field: "distance", Direction: SortDirectionAsc},
			},
			Authenticated: true,
			WantField:     "_sort",
			WantContains:  "requires userLocation",
			SkipMCP:       true, // MCP does not pass sort
		},
		{
			Name: "sort blend_score without blend",
			Request: SearchRequest{
				Sort: &SortInput{Field: "blend_score", Direction: SortDirectionAsc},
			},
			Authenticated: true,
			WantField:     "_sort",
			WantContains:  "requires an active ranking blend",
			SkipMCP:       true,
		},
		{
			Name: "sort by name is valid",
			Request: SearchRequest{
				Sort: &SortInput{Field: "name", Direction: SortDirectionAsc},
			},
			Authenticated: true,
			WantValid:     true,
			SkipMCP:       true,
		},
		{
			Name: "sort unknown field",
			Request: SearchRequest{
				Sort: &SortInput{Field: "bogus_field", Direction: SortDirectionAsc},
			},
			Authenticated: true,
			WantField:     "_sort",
			WantContains:  "unknown sort field",
			SkipMCP:       true,
		},

		// ── Location ────────────────────────────────────────────────
		{
			Name: "valid user location",
			Request: SearchRequest{
				UserLocation: &UserLocation{Latitude: 42.0, Longitude: -72.0, State: "MA"},
			},
			Authenticated: true,
			WantValid:     true,
		},
		{
			Name: "invalid latitude",
			Request: SearchRequest{
				UserLocation: &UserLocation{Latitude: 91.0, Longitude: -72.0},
			},
			Authenticated: true,
			WantField:     "_userLocation",
			WantContains:  "latitude",
		},
		{
			Name: "invalid state code",
			Request: SearchRequest{
				UserLocation: &UserLocation{Latitude: 42.0, Longitude: -72.0, State: "m"},
			},
			Authenticated: true,
			WantField:     "_userLocation",
			WantContains:  "2-letter uppercase",
		},

		// ── Pagination ──────────────────────────────────────────────
		{
			Name: "limit exceeds max",
			Request: SearchRequest{
				Limit: 9999,
			},
			Authenticated: true,
			WantField:     "_limit",
			WantContains:  "limit exceeds",
			SkipExport:    true, // export overrides limit to maxRows
		},
		{
			Name: "negative offset",
			Request: SearchRequest{
				Offset: -1,
			},
			Authenticated: true,
			WantField:     "_offset",
			WantContains:  "offset must be non-negative",
			SkipExport:    true, // export has no offset
		},

		// ── Geo filters ─────────────────────────────────────────────
		{
			Name: "valid geo radius filter",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "location", Value: json.RawMessage(`{"kind":"radius","radius":{"lat":42.0,"lng":-72.0,"radius_km":50}}`)},
				},
			},
			Authenticated: true,
			WantValid:     true,
		},
		{
			Name: "geo radius exceeds max",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "location", Value: json.RawMessage(`{"kind":"radius","radius":{"lat":42.0,"lng":-72.0,"radius_km":9999}}`)},
				},
			},
			Authenticated: true,
			WantField:     "location",
			WantContains:  "exceeds maximum",
		},
		{
			Name: "geo radius not positive",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "location", Value: json.RawMessage(`{"kind":"radius","radius":{"lat":42.0,"lng":-72.0,"radius_km":0}}`)},
				},
			},
			Authenticated: true,
			WantField:     "location",
			WantContains:  "radius must be positive",
		},
	}
}

