package mcp

import (
	"context"
	"encoding/json"
	"strings"
	"testing"

	"github.com/modelcontextprotocol/go-sdk/mcp"

	"github.com/ketang/kapow/api/internal/auth"
	"github.com/ketang/kapow/api/internal/search"
)

// TestContractMatrix_MCP runs the shared contract cases through the MCP
// search handler, verifying that the MCP adapter produces the same
// validation outcomes as the baseline.
func TestContractMatrix_MCP(t *testing.T) {
	t.Parallel()
	defaultReg := search.NewRegistry()

	for _, cc := range search.ContractCases() {
		if cc.SkipMCP {
			continue
		}

		t.Run(cc.Name, func(t *testing.T) {
			t.Parallel()

			reg := defaultReg
			if cc.Registry != nil {
				reg = cc.Registry
			}

			handler := makeSearchHandler(nil, reg)

			in := searchInput{
				Filters: cc.Request.Filters,
				Limit:   cc.Request.Limit,
				Offset:  cc.Request.Offset,
			}

			ctx := context.Background()
			if cc.Authenticated {
				ctx = auth.SetClaims(ctx, &auth.Claims{})
			}

			if cc.WantValid {
				// Validation passes → handler proceeds to DB call → nil Querier panics.
				defer func() {
					if rec := recover(); rec == nil {
						t.Fatal("expected panic from nil DB (validation should have passed)")
					}
					// Panic from nil Querier = validation passed ✓
				}()
				_, _, _ = handler(ctx, nil, in)
				return
			}

			// Expect validation failure → IsError=true.
			result, _, err := handler(ctx, nil, in)
			if err != nil {
				t.Fatalf("unexpected Go error: %v", err)
			}
			if !result.IsError {
				t.Fatal("expected IsError=true for invalid request")
			}

			text, ok := result.Content[0].(*mcp.TextContent)
			if !ok {
				t.Fatalf("expected TextContent, got %T", result.Content[0])
			}

			var body struct {
				Errors []struct {
					Field   string `json:"field"`
					Message string `json:"message"`
				} `json:"errors"`
			}
			if err := json.Unmarshal([]byte(text.Text), &body); err != nil {
				t.Fatalf("decode error response: %v", err)
			}
			if len(body.Errors) == 0 {
				t.Fatal("expected validation errors in response")
			}

			found := false
			for _, e := range body.Errors {
				if e.Field == cc.WantField && strings.Contains(e.Message, cc.WantContains) {
					found = true
					break
				}
			}
			if !found {
				t.Errorf("expected error field=%q containing %q, got: %+v",
					cc.WantField, cc.WantContains, body.Errors)
			}
		})
	}
}

