				Sort: &SortInput{Field: "name", Direction: SortDirectionAsc},
			},
			Authenticated: true,
			WantValid:     true,
			SkipMCP:       true,
		},
		{
			Name: "sort unknown field",
			Request: SearchRequest{
				Sort: &SortInput{Field: "bogus_field", Direction: SortDirectionAsc},
			},
			Authenticated: true,
			WantField:     "_sort",
			WantContains:  "unknown sort field",
			SkipMCP:       true,
		},

		// ── Location ────────────────────────────────────────────────
		{
			Name: "valid user location",
			Request: SearchRequest{
				UserLocation: &UserLocation{Latitude: 42.0, Longitude: -72.0, State: "MA"},
			},
			Authenticated: true,
			WantValid:     true,
		},
		{
			Name: "invalid latitude",
			Request: SearchRequest{
				UserLocation: &UserLocation{Latitude: 91.0, Longitude: -72.0},
			},
			Authenticated: true,
			WantField:     "_userLocation",
			WantContains:  "latitude",
		},
		{
			Name: "invalid state code",
			Request: SearchRequest{
				UserLocation: &UserLocation{Latitude: 42.0, Longitude: -72.0, State: "m"},
			},
			Authenticated: true,
			WantField:     "_userLocation",
			WantContains:  "2-letter uppercase",
		},

		// ── Pagination ──────────────────────────────────────────────
		{
			Name: "limit exceeds max",
			Request: SearchRequest{
				Limit: 9999,
			},
			Authenticated: true,
			WantField:     "_limit",
			WantContains:  "limit exceeds",
			SkipExport:    true, // export overrides limit to maxRows
		},
		{
			Name: "negative offset",
			Request: SearchRequest{
				Offset: -1,
			},
			Authenticated: true,
			WantField:     "_offset",
			WantContains:  "offset must be non-negative",
			SkipExport:    true, // export has no offset
		},

		// ── Geo filters ─────────────────────────────────────────────
		{
			Name: "valid geo radius filter",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "location", Value: json.RawMessage(`{"kind":"radius","radius":{"lat":42.0,"lng":-72.0,"radius_km":50}}`)},
				},
			},
			Authenticated: true,
			WantValid:     true,
		},
		{
			Name: "geo radius exceeds max",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "location", Value: json.RawMessage(`{"kind":"radius","radius":{"lat":42.0,"lng":-72.0,"radius_km":9999}}`)},
				},
			},
			Authenticated: true,
			WantField:     "location",
			WantContains:  "exceeds maximum",
		},
		{
			Name: "geo radius not positive",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "location", Value: json.RawMessage(`{"kind":"radius","radius":{"lat":42.0,"lng":-72.0,"radius_km":0}}`)},
				},
			},
			Authenticated: true,
			WantField:     "location",
			WantContains:  "radius must be positive",
		},
	}
}

